// Define the trigger condition
const triggerCondition = {
 type: 'weekday',
 value: 'Thursday',
 time: '9:00 AM'
};

// Define the action to be performed
const action = {
 type: 'sendMessage',
 channel: 'slack',
 message: 'Latest HSH Nordbank Wochenbarometer report: <link to report>'
};

// Define the filter function
const filter = (event) => {
 // Check if the event is a message event
 if (event.type !== 'message') {
   return false;
 }

 // Check if the event is a message from the specified channel
 if (event.channel !== 'slack') {
   return false;
 }

 // Check if the event is a message that matches the trigger condition
 if (!triggerCondition.test(event.message)) {
   return false;
 }

 // Check if the event is a message that matches the action condition
 if (!action.test(event.message)) {
   return false;
 }

 // If all conditions are met, return true to trigger the action
 return true;
};

// Export the filter function
module.exports = filter;
```

